"use client";

import { Menu as MenuRoot, type MenuProps } from "./menu";
import { MenuItem, type MenuItemProps } from "./menu-item";
import { MenuItemCheckbox, type MenuItemCheckboxProps } from "./menu-item-checkbox";
import { MenuItemRadio, type MenuItemRadioProps } from "./menu-item-radio";
import { MenuDivider, type MenuDividerProps } from "./menu-divider";
import { MenuGroup, type MenuGroupProps } from "./menu-group";
import { MenuLabel, type MenuLabelProps } from "./menu-label";
import { MenuSub, MenuSubTrigger, MenuSubContent, menuSubTriggerBase, type MenuSubProps, type MenuSubTriggerProps, type MenuSubContentProps, type MenuSubTriggerVariantProps } from "./menu-sub";

const Menu = Object.assign(MenuRoot, {
  Item: MenuItem,
  ItemCheckbox: MenuItemCheckbox,
  ItemRadio: MenuItemRadio,
  Divider: MenuDivider,
  Group: MenuGroup,
  Label: MenuLabel,
  Sub: MenuSub,
  SubTrigger: MenuSubTrigger,
  SubContent: MenuSubContent,
});

export { Menu, type MenuProps };
export { MenuItem, type MenuItemProps };
export { MenuItemCheckbox, type MenuItemCheckboxProps };
export { MenuItemRadio, type MenuItemRadioProps };
export { MenuDivider, type MenuDividerProps };
export { MenuGroup, type MenuGroupProps };
export { MenuLabel, type MenuLabelProps };
export { MenuSub, type MenuSubProps };
export { MenuSubTrigger, menuSubTriggerBase, type MenuSubTriggerProps, type MenuSubTriggerVariantProps };
export { MenuSubContent, type MenuSubContentProps };

"use client";

import {
  Children,
  isValidElement,
  type ReactNode,
  type KeyboardEvent,
  type ComponentPropsWithRef,
  type ElementType,
  useCallback,
  useId,
  useMemo,
  useRef,
} from "react";
import { type ListboxMetadataItem, getEncodedListboxItemId, useListbox } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { composeRefs } from "@/lib/compose-refs";
import { MenuContext, type CustomActivator, type MenuContextValue } from "./menu-context";
import { MenuItem } from "./menu-item";
import { MenuItemCheckbox } from "./menu-item-checkbox";
import { MenuItemRadio } from "./menu-item-radio";
import { MenuSubTrigger, MenuSubContent } from "./menu-sub";

export interface MenuProps<TId extends string = string>
  extends Omit<ComponentPropsWithRef<"div">, "children" | "onKeyDown" | "onSelect"> {
  selectedId?: TId | null;
  defaultSelectedId?: TId | null;
  highlighted?: TId | null;
  defaultHighlighted?: TId | null;
  onSelect?: (id: TId) => void;
  onHighlightChange?: (value: TId | null) => void;
  onClose?: () => void;
  variant?: "default" | "hub";
  wrap?: boolean;
  children: ReactNode;
  autoFocus?: boolean;
  onKeyDown?: (event: KeyboardEvent) => void;
}

const MENU_ITEM_TYPES: ElementType[] = [MenuItem, MenuItemCheckbox, MenuItemRadio, MenuSubTrigger];

function collectMenuItems<TId extends string = string>(
  children: ReactNode,
): ListboxMetadataItem<TId>[] {
  const items: ListboxMetadataItem<TId>[] = [];

  Children.forEach(children, (child) => {
    if (!isValidElement<{ id?: string; disabled?: boolean; children?: ReactNode }>(child)) return;

    if (MENU_ITEM_TYPES.includes(child.type as ElementType)) {
      if (typeof child.props.id === "string") {
        items.push({ id: child.props.id as TId, disabled: child.props.disabled });
      }
      return;
    }

    if (child.type === MenuSubContent) return;

    items.push(...collectMenuItems<TId>(child.props.children));
  });

  return items;
}

export function Menu<TId extends string = string>({
  selectedId: controlledSelectedId,
  defaultSelectedId = null,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onHighlightChange,
  onClose,
  variant = "default",
  wrap = true,
  className,
  "aria-label": ariaLabel,
  autoFocus,
  children,
  onKeyDown,
  ref,
  ...rootProps
}: MenuProps<TId>) {
  const idPrefix = useId();
  const menuRef = useRef<HTMLDivElement>(null);
  const customActivators = useRef<Map<string, CustomActivator>>(new Map());
  const selectionEnabled = controlledSelectedId !== undefined || defaultSelectedId !== null;
  const itemRole = selectionEnabled ? "menuitemradio" : "menuitem";
  const items = useMemo(() => collectMenuItems<TId>(children), [children]);

  const registerActivator = useCallback((id: string, handler: CustomActivator) => {
    customActivators.current.set(id, handler);
  }, []);

  const unregisterActivator = useCallback((id: string) => {
    customActivators.current.delete(id);
  }, []);

  const {
    selectedId,
    highlighted,
    handleItemActivate,
    handleItemHighlight,
    getContainerProps,
  } = useListbox<TId>({
    selectedId: selectionEnabled ? controlledSelectedId : null,
    defaultSelectedId: selectionEnabled ? defaultSelectedId : null,
    highlighted: controlledHighlighted,
    defaultHighlighted,
    onSelect,
    onHighlightChange,
    wrap,
    idPrefix,
    onKeyDown: (e: KeyboardEvent) => {
      if ((e.key === "Enter" || e.key === " ") && highlighted !== null) {
        const handler = customActivators.current.get(highlighted);
        if (handler) {
          e.preventDefault();
          handler();
          return;
        }
      }
      if (e.key === "ArrowRight") {
        const container = menuRef.current;
        const activeId = container?.getAttribute("aria-activedescendant");
        if (activeId) {
          const activeEl = container?.ownerDocument.getElementById(activeId);
          if (activeEl?.getAttribute("aria-haspopup") === "menu") {
            e.preventDefault();
            activeEl.click();
            return;
          }
        }
      }
      if (e.key === "Escape") onClose?.();
      if (e.key === "Tab") onClose?.();
      onKeyDown?.(e);
    },
    role: "menu",
    itemRole,
    typeahead: true,
    autoFocus,
    items,
    getItemId: getEncodedListboxItemId,
  });

  const wrappedActivate = useCallback((id: string) => {
    const handler = customActivators.current.get(id);
    if (handler) {
      handleItemHighlight(id as TId);
      handler();
      return;
    }
    handleItemActivate(id as TId);
  }, [handleItemActivate, handleItemHighlight]);

  // Public TId narrows the API; internal context stays string-keyed because the
  // DOM uses data-value strings and child MenuItem ids are opaque to TS.
  const contextValue: MenuContextValue = useMemo(
    () => ({
      selectedId,
      highlighted,
      activate: wrappedActivate,
      highlight: handleItemHighlight as (id: string) => void,
      variant,
      idPrefix,
      itemRole,
      registerActivator,
      unregisterActivator,
    }),
    [selectedId, highlighted, wrappedActivate, handleItemHighlight, variant, idPrefix, itemRole, registerActivator, unregisterActivator],
  );

  return (
    <MenuContext value={contextValue}>
      <div
        {...rootProps}
        {...getContainerProps(composeRefs(menuRef, ref))}
        aria-label={ariaLabel}
        className={cn("w-full relative outline-none", className)}
      >
        {children}
      </div>
    </MenuContext>
  );
}

"use client";

import type { ComponentPropsWithRef, FocusEvent, MouseEvent, ReactNode, Ref } from "react";
import { cva } from "class-variance-authority";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useMenuContext } from "./menu-context";

const INDICATOR_ACTIVE = "\u258C";
const INDICATOR_IDLE = ">";

function MenuItemIndicator({ isFocused, isSelected, className }: { isFocused: boolean; isSelected: boolean; className?: string }) {
  return (
    <span
      aria-hidden="true"
      className={cn(
        "pr-4 shrink-0 inline-flex w-5 items-center justify-center self-center leading-none relative -top-[2px]",
        className,
      )}
    >
      {isFocused || isSelected ? INDICATOR_ACTIVE : INDICATOR_IDLE}
    </span>
  );
}

function MenuItemIconSlot({
  icon,
  isFocused,
  isSelected,
  iconIdleClassName,
  indicatorIdleClassName,
}: {
  icon?: ReactNode;
  isFocused: boolean;
  isSelected: boolean;
  iconIdleClassName?: string;
  indicatorIdleClassName?: string;
}) {
  if (icon !== undefined) {
    const isEmphasized = isFocused || isSelected;
    return (
      <span
        aria-hidden="true"
        className={cn(
          "pr-4 shrink-0 inline-flex w-5 items-center justify-center self-center leading-none relative -top-[2px]",
          !isEmphasized && iconIdleClassName,
        )}
      >
        {icon}
      </span>
    );
  }
  return (
    <MenuItemIndicator
      isFocused={isFocused}
      isSelected={isSelected}
      className={indicatorIdleClassName}
    />
  );
}

interface DefaultItemLayoutProps {
  isFocused: boolean;
  isSelected: boolean;
  isDanger: boolean;
  hotkey?: number | string;
  icon?: ReactNode;
  children: ReactNode;
}

function DefaultItemLayout({ isFocused, isSelected, isDanger, hotkey, icon, children }: DefaultItemLayoutProps) {
  const idleColor = isDanger ? "text-destructive" : "text-foreground";
  const isEmphasized = isFocused || isSelected;

  return (
    <>
      <MenuItemIconSlot
        icon={icon}
        isFocused={isFocused}
        isSelected={isSelected}
        iconIdleClassName={isEmphasized ? undefined : idleColor}
        indicatorIdleClassName={isEmphasized ? undefined : cn("transition-opacity opacity-0 group-hover:opacity-100", idleColor)}
      />
      {hotkey !== undefined && (
        <span
          aria-hidden="true"
          className={isEmphasized ? "mr-4 shrink-0" : cn("mr-4 shrink-0 group-hover:text-foreground", idleColor)}
        >
          [{hotkey}]
        </span>
      )}
      <span className={cn("tracking-wide", !isEmphasized && !isDanger && "group-hover:text-foreground")}>
        {children}
      </span>
    </>
  );
}

interface HubItemLayoutProps {
  isFocused: boolean;
  isSelected: boolean;
  value?: ReactNode;
  valueClassName: string;
  icon?: ReactNode;
  children: ReactNode;
}

function HubItemLayout({
  isFocused,
  isSelected,
  value,
  valueClassName,
  icon,
  children,
}: HubItemLayoutProps) {
  const isEmphasized = isFocused || isSelected;

  return (
    <>
      <div className="flex items-center">
        <MenuItemIconSlot
          icon={icon}
          isFocused={isFocused}
          isSelected={isSelected}
          indicatorIdleClassName={
            !isEmphasized ? "text-foreground opacity-0 group-hover:opacity-100 transition-opacity" : undefined
          }
        />
        <span className={isEmphasized ? undefined : "font-medium group-hover:text-foreground"}>
          {children}
        </span>
      </div>
      {value !== undefined && value !== null && <div className={valueClassName}>{value}</div>}
    </>
  );
}

export type ItemState = "normal" | "focused" | "selected" | "disabled" | "disabledFocused";

export function getItemState(disabled: boolean, isFocused: boolean, isSelected: boolean): ItemState {
  if (disabled && isFocused) return "disabledFocused";
  if (disabled) return "disabled";
  if (isFocused) return "focused";
  if (isSelected) return "selected";
  return "normal";
}

export const menuItemBase = cva("cursor-pointer w-full transition-colors", {
  variants: {
    menuVariant: {
      default: "px-4 py-3 flex items-center font-mono duration-75",
      hub: "px-4 py-4 flex justify-between items-center text-sm border-b border-border last:border-b-0",
    },
      state: {
        normal: "hover:bg-secondary group",
        focused: "font-bold",
        selected: "font-bold group",
        disabled: "opacity-50 cursor-not-allowed",
        disabledFocused: "opacity-60 cursor-not-allowed bg-secondary text-foreground",
      },
    colorVariant: {
      default: "",
      danger: "",
    },
  },
  compoundVariants: [
    { state: "focused", menuVariant: "hub", class: "shadow-[inset_0_0_15px_rgba(0,0,0,0.1)]" },
    { state: "disabled", menuVariant: "default", class: "hover:bg-transparent" },
    { state: "disabledFocused", menuVariant: "hub", class: "shadow-[inset_0_0_15px_rgba(0,0,0,0.1)]" },
    { colorVariant: "danger", state: "focused", class: "bg-destructive text-destructive-foreground" },
    { colorVariant: "default", state: "focused", class: "bg-primary text-primary-foreground" },
    { colorVariant: "danger", state: "selected", class: "bg-destructive text-destructive-foreground" },
    { colorVariant: "default", state: "selected", class: "bg-primary text-primary-foreground" },
    { colorVariant: "danger", state: "normal", menuVariant: "default", class: "text-destructive" },
  ],
  defaultVariants: { menuVariant: "default", state: "normal", colorVariant: "default" },
});

export const menuItemIndicator = cva(
  "pr-4 shrink-0 inline-flex items-center justify-center self-center leading-none font-mono text-xs",
  {
    variants: {
      idle: {
        true: "transition-opacity opacity-60 group-hover:opacity-100",
        false: "",
      },
    },
    defaultVariants: { idle: false },
  },
);

export const menuItemLabel = cva("tracking-wide", {
  variants: {
    idle: {
      true: "group-hover:text-foreground",
      false: "",
    },
  },
  defaultVariants: { idle: false },
});

export const menuItemValue = cva("font-mono text-xs", {
  variants: {
    valueVariant: {
      default: "",
      success: "",
      "success-badge": "border px-2 py-0.5 rounded",
      muted: "",
    },
    focused: {
      true: "uppercase tracking-wide",
      false: "",
    },
    active: {
      true: "",
      false: "",
    },
  },
  compoundVariants: [
    {
      valueVariant: "default",
      active: false,
      class: "text-muted-foreground",
    },
    {
      valueVariant: "success",
      active: false,
      class: "text-success",
    },
    {
      valueVariant: "success-badge",
      active: false,
      class: "text-success border-success/30 bg-success/10",
    },
    {
      valueVariant: "muted",
      active: false,
      class: "text-muted-foreground/60",
    },
    {
      valueVariant: "default",
      active: true,
      class: "text-current",
    },
    {
      valueVariant: "success",
      active: true,
      class: "text-current",
    },
    {
      valueVariant: "muted",
      active: true,
      class: "text-current",
    },
    {
      valueVariant: "success-badge",
      active: true,
      class: "border-success bg-success text-success-foreground",
    },
  ],
  defaultVariants: { valueVariant: "default", focused: false, active: false },
});

export interface MenuItemProps<TId extends string = string>
  extends Omit<
    ComponentPropsWithRef<"div">,
    "id" | "children" | "role" | "aria-checked" | "aria-disabled" | "data-value" | "ref"
  > {
  id: TId;
  disabled?: boolean;
  variant?: "default" | "danger";
  hotkey?: number | string;
  icon?: ReactNode;
  value?: ReactNode;
  valueVariant?: "default" | "success" | "success-badge" | "muted";
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export function MenuItem<TId extends string = string>({
  id,
  disabled = false,
  variant = "default",
  hotkey,
  icon,
  value,
  valueVariant = "default",
  children,
  className,
  ref,
  onClick,
  onFocus,
  onMouseDown,
  ...rootProps
}: MenuItemProps<TId>) {
  const { selectedId, highlighted, activate, highlight, variant: menuVariant, idPrefix, itemRole } =
    useMenuContext();

  const isSelected = !disabled && selectedId === id;
  const isFocused = highlighted === id;
  const isActive = !disabled && (isFocused || isSelected);
  const isDanger = variant === "danger";
  const isHub = menuVariant === "hub";
  const state = getItemState(disabled, isFocused, isSelected);
  const itemId = getEncodedListboxItemId(idPrefix, id);

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (event.defaultPrevented || disabled) return;
    activate(id);
  };

  const handleFocus = (event: FocusEvent<HTMLDivElement>) => {
    onFocus?.(event);
    if (event.defaultPrevented || disabled) return;
    highlight(id);
  };

  const handleMouseDown = (event: MouseEvent<HTMLDivElement>) => {
    onMouseDown?.(event);
    if (event.defaultPrevented) return;
    if (disabled) event.preventDefault();
  };

  return (
    <div
      {...rootProps}
      ref={ref}
      id={itemId}
      role={itemRole}
      tabIndex={-1}
      data-diffgazer-navigation-item="true"
      data-value={id}
      data-active={isActive || undefined}
      data-focus={isFocused || undefined}
      aria-checked={itemRole === "menuitemradio" ? isSelected : undefined}
      aria-disabled={disabled || undefined}
      data-state={isSelected ? "selected" : "unselected"}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(menuItemBase({ menuVariant, state, colorVariant: variant }), className)}
    >
      {isHub ? (
        <HubItemLayout
          isFocused={isFocused}
          isSelected={isSelected}
          value={value}
          valueClassName={menuItemValue({ valueVariant, focused: isActive, active: isActive })}
          icon={icon}
        >
          {children}
        </HubItemLayout>
      ) : (
        <DefaultItemLayout isFocused={isFocused} isSelected={isSelected} isDanger={isDanger} hotkey={hotkey} icon={icon}>
          {children}
        </DefaultItemLayout>
      )}
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";

export interface MenuDividerProps {
  className?: string;
}

export function MenuDivider({ className }: MenuDividerProps) {
  return (
    <div
      role="separator"
      aria-orientation="horizontal"
      className={cn("my-1 border-t border-border mx-4 opacity-50", className)}
    />
  );
}

"use client";

import { createContext, useContext } from "react";

export type CustomActivator = () => void;

export interface MenuContextValue {
  selectedId: string | null;
  highlighted: string | null;
  activate: (id: string) => void;
  highlight: (id: string) => void;
  variant: "default" | "hub";
  idPrefix: string;
  itemRole: "menuitem" | "menuitemradio";
  registerActivator: (id: string, handler: CustomActivator) => void;
  unregisterActivator: (id: string) => void;
}

export const MenuContext = createContext<MenuContextValue | undefined>(undefined);

export function useMenuContext(): MenuContextValue {
  const context = useContext(MenuContext);
  if (context === undefined) {
    throw new Error("Menu parts must be used within a Menu");
  }
  return context;
}

"use client";

import { useId, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { MenuLabel } from "./menu-label";

export interface MenuGroupProps {
  label?: ReactNode;
  children: ReactNode;
  className?: string;
}

export function MenuGroup({ label, children, className }: MenuGroupProps) {
  const labelId = useId();
  const hasLabel = label !== undefined && label !== null;

  return (
    <div
      role="group"
      aria-labelledby={hasLabel ? labelId : undefined}
      className={cn(className)}
    >
      {hasLabel && <MenuLabel id={labelId}>{label}</MenuLabel>}
      {children}
    </div>
  );
}

"use client";

import {
  useEffect,
  type ComponentPropsWithRef,
  type FocusEvent,
  type MouseEvent,
  type ReactNode,
  type Ref,
} from "react";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { useControllableState } from "@/hooks/use-controllable-state";
import { cn } from "@/lib/utils";
import { useMenuContext } from "./menu-context";
import { getItemState, menuItemBase, menuItemIndicator, menuItemLabel } from "./menu-item";

const CHECKBOX_CHECKED = "[x]";
const CHECKBOX_UNCHECKED = "[ ]";

export interface MenuItemCheckboxProps
  extends Omit<
    ComponentPropsWithRef<"div">,
    "id" | "children" | "role" | "aria-checked" | "aria-disabled" | "data-value" | "onChange" | "ref"
  > {
  id: string;
  checked?: boolean;
  defaultChecked?: boolean;
  onChange?: (checked: boolean) => void;
  disabled?: boolean;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export function MenuItemCheckbox({
  id,
  checked: controlledChecked,
  defaultChecked = false,
  onChange,
  disabled = false,
  children,
  className,
  ref,
  onClick,
  onFocus,
  onMouseDown,
  ...rootProps
}: MenuItemCheckboxProps) {
  const { highlighted, activate, highlight, idPrefix, registerActivator, unregisterActivator } =
    useMenuContext();

  const [isChecked, setIsChecked] = useControllableState<boolean>({
    value: controlledChecked,
    defaultValue: defaultChecked,
    onChange,
  });

  const isFocused = highlighted === id;
  const itemId = getEncodedListboxItemId(idPrefix, id);

  useEffect(() => {
    const toggle = () => {
      if (disabled) return;
      setIsChecked((prev) => !prev);
    };
    registerActivator(id, toggle);
    return () => unregisterActivator(id);
  }, [id, disabled, registerActivator, unregisterActivator, setIsChecked]);

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (event.defaultPrevented || disabled) return;
    activate(id);
  };

  const handleFocus = (event: FocusEvent<HTMLDivElement>) => {
    onFocus?.(event);
    if (event.defaultPrevented || disabled) return;
    highlight(id);
  };

  const handleMouseDown = (event: MouseEvent<HTMLDivElement>) => {
    onMouseDown?.(event);
    if (event.defaultPrevented) return;
    if (disabled) event.preventDefault();
  };

  const state = getItemState(disabled, isFocused, false);

  return (
    <div
      {...rootProps}
      ref={ref}
      id={itemId}
      role="menuitemcheckbox"
      tabIndex={-1}
      data-diffgazer-navigation-item="true"
      data-value={id}
      data-active={(!disabled && isFocused) || undefined}
      data-focus={isFocused || undefined}
      aria-checked={isChecked}
      aria-disabled={disabled || undefined}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(menuItemBase({ menuVariant: "default", state, colorVariant: "default" }), className)}
    >
      <span
        aria-hidden="true"
        className={menuItemIndicator({ idle: !isFocused && !disabled || undefined })}
      >
        {isChecked ? CHECKBOX_CHECKED : CHECKBOX_UNCHECKED}
      </span>
      <span className={menuItemLabel({ idle: !isFocused && !disabled || undefined })}>
        {children}
      </span>
    </div>
  );
}

"use client";

import type {
  ComponentPropsWithRef,
  FocusEvent,
  MouseEvent,
  ReactNode,
  Ref,
} from "react";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useMenuContext } from "./menu-context";
import { getItemState, menuItemBase, menuItemIndicator, menuItemLabel } from "./menu-item";

const RADIO_SELECTED = "(*)";
const RADIO_UNSELECTED = "( )";

export interface MenuItemRadioProps
  extends Omit<
    ComponentPropsWithRef<"div">,
    "id" | "children" | "role" | "aria-checked" | "aria-disabled" | "data-value" | "ref"
  > {
  id: string;
  value: string;
  disabled?: boolean;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export function MenuItemRadio({
  id,
  value,
  disabled = false,
  children,
  className,
  ref,
  onClick,
  onFocus,
  onMouseDown,
  ...rootProps
}: MenuItemRadioProps) {
  const { selectedId, highlighted, activate, highlight, idPrefix } =
    useMenuContext();

  const isSelected = !disabled && selectedId === id;
  const isFocused = highlighted === id;
  const isActive = !disabled && (isFocused || isSelected);
  const itemId = getEncodedListboxItemId(idPrefix, id);

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (event.defaultPrevented || disabled) return;
    activate(id);
  };

  const handleFocus = (event: FocusEvent<HTMLDivElement>) => {
    onFocus?.(event);
    if (event.defaultPrevented || disabled) return;
    highlight(id);
  };

  const handleMouseDown = (event: MouseEvent<HTMLDivElement>) => {
    onMouseDown?.(event);
    if (event.defaultPrevented) return;
    if (disabled) event.preventDefault();
  };

  const state = getItemState(disabled, isFocused, isSelected);

  return (
    <div
      {...rootProps}
      ref={ref}
      id={itemId}
      role="menuitemradio"
      tabIndex={-1}
      data-diffgazer-navigation-item="true"
      data-value={id}
      data-active={isActive || undefined}
      data-focus={isFocused || undefined}
      aria-checked={isSelected}
      aria-disabled={disabled || undefined}
      data-state={isSelected ? "selected" : "unselected"}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(menuItemBase({ menuVariant: "default", state, colorVariant: "default" }), className)}
    >
      <span
        aria-hidden="true"
        className={menuItemIndicator({ idle: !isActive && !disabled || undefined })}
      >
        {isSelected ? RADIO_SELECTED : RADIO_UNSELECTED}
      </span>
      <span className={menuItemLabel({ idle: !isActive && !disabled || undefined })}>
        {children}
      </span>
    </div>
  );
}

